<span class="line">      <span class="token keyword">style</span> stepLegend <span class="token style"><span class="token property">fill</span><span class="token operator">:</span>#474949<span class="token punctuation">,</span> <span class="token property">stroke</span><span class="token operator">:</span> #CCC<span class="token punctuation">,</span> <span class="token property">color</span><span class="token operator">:</span>#CCC</span></span>
